+fn x509_cert_signing_allowed(certificate: &X509Certificate<'_>) -> Option<bool> {
+    if x509_basic_constraints_ca(certificate) != Some(true) {
+        return Some(false);
+    }
+
+    match certificate.key_usage() {
+        Ok(Some(usage)) => Some(usage.value.key_cert_sign()),
+        Ok(None) => Some(true),
+        Err(_) => None,
+    }
+}
